import React, { useState } from 'react';
import Icon from '../../../components/AppIcon';
import Button from '../../../components/ui/Button';

const AvailabilityCalendar = ({ blockedDates = [], onSelectionChange }) => {
  const [currentMonth, setCurrentMonth] = useState(new Date());
  const [selectedStartDate, setSelectedStartDate] = useState(null);
  const [selectedEndDate, setSelectedEndDate] = useState(null);

  const monthNames = [
    'Janvier', 'Février', 'Mars', 'Avril', 'Mai', 'Juin',
    'Juillet', 'Août', 'Septembre', 'Octobre', 'Novembre', 'Décembre'
  ];

  const dayNames = ['Lun', 'Mar', 'Mer', 'Jeu', 'Ven', 'Sam', 'Dim'];

  const getDaysInMonth = (date) => {
    const year = date?.getFullYear();
    const month = date?.getMonth();
    const firstDay = new Date(year, month, 1);
    const lastDay = new Date(year, month + 1, 0);
    const daysInMonth = lastDay?.getDate();
    const startingDayOfWeek = firstDay?.getDay() === 0 ? 6 : firstDay?.getDay() - 1;

    return { daysInMonth, startingDayOfWeek, year, month };
  };

  const isDateBlocked = (date) => {
    const dateString = date?.toISOString()?.split('T')?.[0];
    return blockedDates?.includes(dateString);
  };

  const isDateSelected = (date) => {
    if (!selectedStartDate) return false;
    const dateString = date?.toISOString()?.split('T')?.[0];
    const startString = selectedStartDate?.toISOString()?.split('T')?.[0];
    const endString = selectedEndDate?.toISOString()?.split('T')?.[0];
    
    if (selectedEndDate) {
      return dateString >= startString && dateString <= endString;
    }
    return dateString === startString;
  };

  const today = new Date();
  today?.setHours(0, 0, 0, 0);

  const emitSelectionChange = (startDate, endDate) => {
    onSelectionChange?.(startDate, endDate);
  };

  const handleDateClick = (date) => {
    if (isDateBlocked(date) || date < today) return;

    if (!selectedStartDate || (selectedStartDate && selectedEndDate)) {
      setSelectedStartDate(date);
      setSelectedEndDate(null);
      emitSelectionChange(date, null);
    } else if (date > selectedStartDate) {
      setSelectedEndDate(date);
      emitSelectionChange(selectedStartDate, date);
    } else {
      setSelectedStartDate(date);
      setSelectedEndDate(null);
      emitSelectionChange(date, null);
    }
  };

  const handlePreviousMonth = () => {
    setCurrentMonth(new Date(currentMonth?.getFullYear(), currentMonth?.getMonth() - 1));
  };

  const handleNextMonth = () => {
    setCurrentMonth(new Date(currentMonth?.getFullYear(), currentMonth?.getMonth() + 1));
  };

  const { daysInMonth, startingDayOfWeek, year, month } = getDaysInMonth(currentMonth);
  const waitingForEndDate = !!selectedStartDate && !selectedEndDate;
  const startDateLabel = selectedStartDate
    ? selectedStartDate?.toLocaleDateString('fr-FR')
    : 'Non choisi';
  const endDateLabel = selectedEndDate
    ? selectedEndDate?.toLocaleDateString('fr-FR')
    : (selectedStartDate ? 'Cliquez sur une date de fin' : 'Choisissez d abord un debut');

  return (
    <div className="space-y-4">
      <div className="rounded-md border border-[#17a2b8]/20 bg-[#17a2b8]/5 p-3">
        <p className="text-sm font-medium text-foreground">
          {!selectedStartDate ? '1. Cliquez sur une date de debut' : waitingForEndDate ? '2. Cliquez sur une date de fin' : 'Periode preselectionnee'}
        </p>
        <p className="text-xs text-muted-foreground mt-1">
          {!selectedStartDate
            ? 'Selectionnez d abord le premier jour, puis le dernier jour de reservation.'
            : waitingForEndDate
              ? 'Choisissez maintenant la date de fin.'
              : 'Les dates seront reprises dans la page de demande de reservation.'}
        </p>
        <div className="grid grid-cols-1 gap-2 mt-3">
          <div className="rounded-md border border-border bg-white px-3 py-2">
            <p className="text-xs text-muted-foreground">Debut</p>
            <p className="text-sm font-medium text-foreground">{startDateLabel}</p>
          </div>
          <div className="rounded-md border border-border bg-white px-3 py-2">
            <p className="text-xs text-muted-foreground">Fin</p>
            <p className="text-sm font-medium text-foreground">{endDateLabel}</p>
          </div>
        </div>
      </div>

      {/* Month Navigation */}
      <div className="flex items-center justify-between">
        <Button
          variant="ghost"
          size="icon"
          onClick={handlePreviousMonth}
          className="h-8 w-8"
        >
          <Icon name="ChevronLeft" size={18} />
        </Button>
        <span className="font-semibold text-foreground">
          {monthNames?.[month]} {year}
        </span>
        <Button
          variant="ghost"
          size="icon"
          onClick={handleNextMonth}
          className="h-8 w-8"
        >
          <Icon name="ChevronRight" size={18} />
        </Button>
      </div>
      {/* Calendar Grid */}
      <div className="grid grid-cols-7 gap-1">
        {/* Day Headers */}
        {dayNames?.map((day) => (
          <div key={day} className="text-center text-xs font-medium text-muted-foreground py-2">
            {day}
          </div>
        ))}

        {/* Empty cells for days before month starts */}
        {Array?.from({ length: startingDayOfWeek })?.map((_, index) => (
          <div key={`empty-${index}`} className="aspect-square" />
        ))}

        {/* Calendar Days */}
        {Array?.from({ length: daysInMonth })?.map((_, index) => {
          const day = index + 1;
          const date = new Date(year, month, day);
          const isBlocked = isDateBlocked(date);
          const isPast = date < today;
          const isSelected = isDateSelected(date);
          const isDisabled = isBlocked || isPast;

          return (
            <button
              key={day}
              onClick={() => handleDateClick(date)}
              disabled={isDisabled}
              className={`aspect-square flex items-center justify-center text-sm rounded-md transition-all ${
                isSelected
                  ? 'bg-[#17a2b8] text-white font-semibold'
                  : isDisabled
                  ? 'text-muted-foreground line-through cursor-not-allowed opacity-50'
                  : 'hover:bg-surface text-foreground cursor-pointer'
              }`}
            >
              {day}
            </button>
          );
        })}
      </div>
      {/* Legend */}
      <div className="flex flex-wrap gap-4 text-xs pt-2 border-t border-border">
        <div className="flex items-center gap-2">
          <div className="w-4 h-4 rounded bg-[#17a2b8]" />
          <span className="text-muted-foreground">Sélectionné</span>
        </div>
        <div className="flex items-center gap-2">
          <div className="w-4 h-4 rounded bg-muted line-through" />
          <span className="text-muted-foreground">Indisponible</span>
        </div>
      </div>
      {/* Selected Dates Summary */}
      {selectedStartDate && (
        <div className="pt-2 border-t border-border">
          <p className="text-sm text-muted-foreground mb-1">Période sélectionnée:</p>
          <p className="text-sm font-semibold text-foreground">
            {selectedStartDate?.toLocaleDateString('fr-FR')}
            {selectedEndDate && ` - ${selectedEndDate?.toLocaleDateString('fr-FR')}`}
          </p>
        </div>
      )}
    </div>
  );
};

export default AvailabilityCalendar;
